SELECT MAX(application_count) AS max_application_count
FROM (
    SELECT COUNT(application_id) AS application_count
    FROM applications
    GROUP BY program_id
) AS subquery;

SELECT COUNT(*) AS total_accepted_applications
FROM applications
WHERE application_status = 'accepted';

SELECT AVG(application_count) AS avg_applications_per_program
FROM (
  SELECT COUNT(*) AS application_count
  FROM applications
  GROUP BY program_id
) AS application_summary;
